import React from 'react';
import '../css/content.css'
import {motion} from 'framer-motion';
const Home = () => {

    return (
        
        <motion.div className="content-wrap"  exit={{opacity:0}} animate={{opacity:1}}  initial={{opacity:0}}>
            <div className="hero">
                <h2 className="hero_title">
                    Whatever you do,<br></br>make it pay
                </h2>
                <p className="hero_sub">I'm webdesigner based in Busan, Republic of Korea</p>
            </div>
            <div className="recent_list">
                <h3 className="sec_title">Recent Work</h3>
                
            </div>
        </motion.div>
    );
};

export default Home;