import React , {useState, useEffect} from 'react';
import {motion} from 'framer-motion';
import '../css/content.css'
const Work = () => {
    const [post, setPost] = useState([]);

    useEffect(() => {
        fetch('https://heavybear.cafe24.com/wp-json/wp/v2/posts/?categories=3')
        .then(res => res.json())
        .then(response => setPost(response))
        .catch(err => console.log(err));

    },[])
   
   console.log(post)
    return (
        <motion.div className="content-wrap"  exit={{opacity:0}} animate={{opacity:1}}  initial={{opacity:0}}>
            <div className="recent_list">
                <ul className="post_list">
                    {post.map((item, index) => (
                        <li key={index}>
                            <h3 className="title">{item.title.rendered}</h3>
                            <p className="summary" dangerouslySetInnerHTML={{__html: item.excerpt.rendered}}></p>
                            <p className="date">{item.date.slice(0,10)}</p>
                        </li>
                    ))}
                </ul>
            </div>
        </motion.div>
    );
};

export default Work;